            }

            if(typeof TFE_IOSPLAYER_SWIPEFULLSCREEN !== 'undefined'){
                configJSON.fullscreen = {
                    enabled: (typeof flashvars.autoFullscreen != "undefined") ? flashvars.autoFullscreen : true,
